use std::path::Path;

use dto_bindgen_backend_ts::{
    TypeScriptDeclaration, TypeScriptModule, TypeScriptParameter, TypeScriptProperty,
    TypeScriptType, TypeScriptValue,
};

use crate::package_matrix::WasmPackageSpec;

const WASM_DECLARATION_HEADER: &str =
    "// @generated by cargo xtask generate wasm via dto_bindgen\n// Do not edit by hand.\n";

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct WasmDeclarationFile {
    pub relative_path: String,
    pub contents: String,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct WasmDeclarationInventory {
    public_functions: &'static [WasmPublicFunction],
    support_exports: &'static [WasmSupportExport],
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct WasmPublicFunction {
    name: &'static str,
    parameter: Option<&'static str>,
    return_kind: WasmReturnKind,
    low_level: LowLevelSignature,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum WasmReturnKind {
    String,
    Any,
    Void,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct LowLevelSignature {
    parameters: usize,
    returns: usize,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct WasmSupportExport {
    name: &'static str,
    export_type: WasmSupportExportType,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum WasmSupportExportType {
    Memory,
    Table,
    Function(LowLevelSignature),
    NumberFunction(usize),
}

macro_rules! public_function {
    ($name:literal, $parameter:expr, $return_kind:ident, $low_parameters:literal, $low_returns:literal) => {
        WasmPublicFunction {
            name: $name,
            parameter: $parameter,
            return_kind: WasmReturnKind::$return_kind,
            low_level: LowLevelSignature {
                parameters: $low_parameters,
                returns: $low_returns,
            },
        }
    };
}

macro_rules! memory_export {
    () => {
        WasmSupportExport {
            name: "memory",
            export_type: WasmSupportExportType::Memory,
        }
    };
}

macro_rules! table_export {
    ($name:literal) => {
        WasmSupportExport {
            name: $name,
            export_type: WasmSupportExportType::Table,
        }
    };
}

macro_rules! void_function_export {
    ($name:literal, $parameters:literal) => {
        WasmSupportExport {
            name: $name,
            export_type: WasmSupportExportType::Function(LowLevelSignature {
                parameters: $parameters,
                returns: 0,
            }),
        }
    };
}

macro_rules! number_function_export {
    ($name:literal, $parameters:literal) => {
        WasmSupportExport {
            name: $name,
            export_type: WasmSupportExportType::NumberFunction($parameters),
        }
    };
}

pub fn write_declaration_files(root: &Path, spec: WasmPackageSpec) -> Result<(), String> {
    let package_dir = root.join(spec.package_dir);
    for file in declaration_files(spec)? {
        crate::fs::write_if_changed(&package_dir.join(&file.relative_path), &file.contents)?;
    }
    Ok(())
}

pub fn declaration_files(spec: WasmPackageSpec) -> Result<Vec<WasmDeclarationFile>, String> {
    let inventory = inventory(spec)?;
    Ok(vec![
        WasmDeclarationFile {
            relative_path: format!("dist/{}.d.ts", spec.out_name),
            contents: render_declaration_module(primary_module(spec, inventory)),
        },
        WasmDeclarationFile {
            relative_path: format!("dist/{}_bg.wasm.d.ts", spec.out_name),
            contents: render_declaration_module(sidecar_module(spec, inventory)),
        },
    ])
}

fn inventory(spec: WasmPackageSpec) -> Result<WasmDeclarationInventory, String> {
    match spec.key {
        "event_codec" => Ok(WasmDeclarationInventory {
            public_functions: EVENT_CODEC_FUNCTIONS,
            support_exports: EVENT_CODEC_SUPPORT_EXPORTS,
        }),
        "replica_store" => Ok(WasmDeclarationInventory {
            public_functions: REPLICA_STORE_FUNCTIONS,
            support_exports: SQL_WASM_SUPPORT_EXPORTS,
        }),
        "replica_sync" => Ok(WasmDeclarationInventory {
            public_functions: REPLICA_SYNC_FUNCTIONS,
            support_exports: SQL_WASM_SUPPORT_EXPORTS,
        }),
        _ => Err(format!(
            "missing wasm declaration inventory for {}",
            spec.key
        )),
    }
}

fn primary_module(spec: WasmPackageSpec, inventory: WasmDeclarationInventory) -> TypeScriptModule {
    let mut module = TypeScriptModule::new(format!("dist/{}.d.ts", spec.out_name));
    for function in inventory.public_functions {
        module.push_declaration(TypeScriptDeclaration::function(
            function.name,
            public_parameters(function.parameter),
            public_return_type(function.return_kind),
        ));
    }
    module.push_declaration(TypeScriptDeclaration::type_alias(
        "InitInput",
        init_input_type(),
    ));
    module.push_declaration(TypeScriptDeclaration::type_alias(
        "InitOutput",
        init_output_type(inventory),
    ));
    module.push_declaration(TypeScriptDeclaration::type_alias(
        "SyncInitInput",
        sync_init_input_type(),
    ));
    module.push_declaration(TypeScriptDeclaration::function(
        "initSync",
        vec![TypeScriptParameter::new(
            "module",
            TypeScriptType::union(vec![
                TypeScriptType::object(vec![TypeScriptProperty::new(
                    "module",
                    TypeScriptType::named("SyncInitInput"),
                )]),
                TypeScriptType::named("SyncInitInput"),
            ]),
        )],
        TypeScriptType::named("InitOutput"),
    ));
    module.push_declaration(TypeScriptDeclaration::default_function(
        "__wbg_init",
        vec![
            TypeScriptParameter::new(
                "module_or_path",
                TypeScriptType::union(vec![
                    TypeScriptType::object(vec![TypeScriptProperty::new(
                        "module_or_path",
                        TypeScriptType::union(vec![
                            TypeScriptType::named("InitInput"),
                            promise_of(TypeScriptType::named("InitInput")),
                        ]),
                    )]),
                    TypeScriptType::named("InitInput"),
                    promise_of(TypeScriptType::named("InitInput")),
                ]),
            )
            .optional(),
        ],
        promise_of(TypeScriptType::named("InitOutput")),
    ));
    module
}

fn sidecar_module(spec: WasmPackageSpec, inventory: WasmDeclarationInventory) -> TypeScriptModule {
    let mut module = TypeScriptModule::new(format!("dist/{}_bg.wasm.d.ts", spec.out_name));
    for export in inventory.support_exports {
        if matches!(export.export_type, WasmSupportExportType::Memory) {
            module.push_declaration(support_export_declaration(*export));
        }
    }
    for function in inventory.public_functions {
        module.push_declaration(TypeScriptDeclaration::constant(
            function.name,
            Some(low_level_function_type(function.low_level)),
            TypeScriptValue::string(""),
        ));
    }
    for export in inventory.support_exports {
        if !matches!(export.export_type, WasmSupportExportType::Memory) {
            module.push_declaration(support_export_declaration(*export));
        }
    }
    module
}

fn render_declaration_module(module: TypeScriptModule) -> String {
    let mut rendered = String::from(WASM_DECLARATION_HEADER);
    rendered.push_str(&module.render_declaration());
    rendered
}

fn public_parameters(parameter: Option<&'static str>) -> Vec<TypeScriptParameter> {
    parameter
        .map(|name| vec![TypeScriptParameter::new(name, TypeScriptType::String)])
        .unwrap_or_default()
}

fn public_return_type(kind: WasmReturnKind) -> TypeScriptType {
    match kind {
        WasmReturnKind::String => TypeScriptType::String,
        WasmReturnKind::Any => TypeScriptType::Any,
        WasmReturnKind::Void => TypeScriptType::Void,
    }
}

fn init_input_type() -> TypeScriptType {
    TypeScriptType::union(vec![
        TypeScriptType::named("RequestInfo"),
        TypeScriptType::named("URL"),
        TypeScriptType::named("Response"),
        TypeScriptType::named("BufferSource"),
        TypeScriptType::named("WebAssembly.Module"),
    ])
}

fn sync_init_input_type() -> TypeScriptType {
    TypeScriptType::union(vec![
        TypeScriptType::named("BufferSource"),
        TypeScriptType::named("WebAssembly.Module"),
    ])
}

fn init_output_type(inventory: WasmDeclarationInventory) -> TypeScriptType {
    let mut properties = vec![TypeScriptProperty::new("memory", memory_type()).readonly()];
    properties.extend(inventory.public_functions.iter().map(|function| {
        TypeScriptProperty::new(function.name, low_level_function_type(function.low_level))
            .readonly()
    }));
    properties.extend(
        inventory
            .support_exports
            .iter()
            .filter(|export| !matches!(export.export_type, WasmSupportExportType::Memory))
            .map(|export| {
                TypeScriptProperty::new(export.name, support_export_type(*export)).readonly()
            }),
    );
    TypeScriptType::object(properties)
}

fn support_export_declaration(export: WasmSupportExport) -> TypeScriptDeclaration {
    TypeScriptDeclaration::constant(
        export.name,
        Some(support_export_type(export)),
        TypeScriptValue::string(""),
    )
}

fn support_export_type(export: WasmSupportExport) -> TypeScriptType {
    match export.export_type {
        WasmSupportExportType::Memory => memory_type(),
        WasmSupportExportType::Table => TypeScriptType::named("WebAssembly.Table"),
        WasmSupportExportType::Function(signature) => low_level_function_type(signature),
        WasmSupportExportType::NumberFunction(parameters) => {
            low_level_number_function_type(parameters)
        }
    }
}

fn memory_type() -> TypeScriptType {
    TypeScriptType::named("WebAssembly.Memory")
}

fn low_level_number_function_type(parameters: usize) -> TypeScriptType {
    TypeScriptType::function(number_parameters(parameters), TypeScriptType::Number)
}

fn low_level_function_type(signature: LowLevelSignature) -> TypeScriptType {
    TypeScriptType::function(
        number_parameters(signature.parameters),
        low_level_return_type(signature.returns),
    )
}

fn number_parameters(count: usize) -> Vec<TypeScriptParameter> {
    (0..count)
        .map(|index| {
            TypeScriptParameter::new(low_level_parameter_name(index), TypeScriptType::Number)
        })
        .collect()
}

fn low_level_parameter_name(index: usize) -> String {
    match index {
        0 => "a".to_owned(),
        1 => "b".to_owned(),
        2 => "c".to_owned(),
        3 => "d".to_owned(),
        _ => format!("arg{index}"),
    }
}

fn low_level_return_type(count: usize) -> TypeScriptType {
    match count {
        0 => TypeScriptType::Void,
        1 => TypeScriptType::Number,
        _ => TypeScriptType::tuple(vec![TypeScriptType::Number; count]),
    }
}

fn promise_of(type_expr: TypeScriptType) -> TypeScriptType {
    TypeScriptType::generic("Promise", vec![type_expr])
}

