#[cfg(test)]
mod tests {
    use crate::package_matrix::wasm_package_specs;

    use super::{WASM_DECLARATION_HEADER, declaration_files};

    #[test]
    fn declaration_files_are_dto_owned_and_cover_primary_and_sidecar_paths() {
        for spec in wasm_package_specs() {
            let files = declaration_files(*spec).expect("declaration files");
            assert_eq!(files.len(), 2);
            assert!(
                files
                    .iter()
                    .any(|file| file.relative_path == format!("dist/{}.d.ts", spec.out_name))
            );
            assert!(
                files.iter().any(
                    |file| file.relative_path == format!("dist/{}_bg.wasm.d.ts", spec.out_name)
                )
            );
            for file in files {
                assert!(file.contents.starts_with(WASM_DECLARATION_HEADER));
                assert!(!file.contents.contains("tslint:disable"));
                assert!(!file.contents.contains("eslint-disable"));
            }
        }
    }

    #[test]
    fn generated_declarations_include_public_wasm_entrypoints() {
        let specs = wasm_package_specs();
        let events = declaration_files(specs[0]).expect("event declarations");
        assert!(
            events[0]
                .contents
                .contains("export function operational_listing_tags")
        );
        assert!(
            events[1]
                .contents
                .contains("export declare const operational_listing_tags")
        );
        for authored in [
            "social_ask_build_authored_draft",
            "social_comment_build_authored_draft",
            "social_photo_update_build_authored_draft",
            "social_update_build_authored_draft",
        ] {
            assert!(
                events[0]
                    .contents
                    .contains(&format!("export function {authored}"))
            );
            assert!(
                events[1]
                    .contents
                    .contains(&format!("export declare const {authored}"))
            );
        }
        for retired in [
            "calendar_date_event_tags",
            "calendar_event_rsvp_tags",
            "calendar_tags",
            "calendar_time_event_tags",
        ] {
            assert!(!events[0].contents.contains(retired));
            assert!(!events[1].contents.contains(retired));
        }
        for retired in ["comment_tags", "post_tags"] {
            assert!(
                !events[0]
                    .contents
                    .contains(&format!("export function {retired}("))
            );
            assert!(
                !events[1]
                    .contents
                    .contains(&format!("export declare const {retired}:"))
            );
        }

        let replica_store = declaration_files(specs[1]).expect("replica store declarations");
        assert!(
            replica_store[0]
                .contents
                .contains("export function replica_store_farm_create")
        );
        assert!(
            replica_store[0]
                .contents
                .contains("export function replica_store_farm_update")
        );
        assert!(
            replica_store[0]
                .contents
                .contains("export function replica_store_plot_update")
        );
        assert!(
            replica_store[1]
                .contents
                .contains("export declare const replica_store_farm_create")
        );
        assert!(
            replica_store[1]
                .contents
                .contains("export declare const replica_store_farm_update")
        );
        assert!(
            replica_store[1]
                .contents
                .contains("export declare const replica_store_plot_update")
        );

        let replica_sync = declaration_files(specs[2]).expect("replica sync declarations");
        assert!(
            replica_sync[0]
                .contents
                .contains("export function replica_sync_sync_all")
        );
        assert!(
            replica_sync[1]
                .contents
                .contains("export declare const replica_sync_sync_all")
        );
    }
}
